import 'package:bookly/Core/Utils/constant.dart';import 'package:bookly/Core/Utils/extensions.dart';import 'package:bookly/Core/Utils/text_style.dart';import 'package:bookly/Features/Home/ViewModel/NewsBooksCubit/news_books_cubit.dart';import 'package:bookly/Features/Home/ViewModel/NewsBooksCubit/news_books_state.dart';import 'package:flutter/material.dart';import 'package:flutter_bloc/flutter_bloc.dart';import '../../../../ViewBooks/View/view_book.dart';const String _title = "Best Seller";class BestSellerBuilder extends StatelessWidget {  const BestSellerBuilder({super.key});  @override  Widget build(BuildContext context) {    return BlocConsumer<NewsBooksCubit, NewsBooksState>(      listener: (context, state) {},      builder: (context, state) {        if (state is NewsBooksSuccess) {          return Padding(              padding: const EdgeInsets.only(top: 20, right: 30, left: 40),              child: Column(                crossAxisAlignment: CrossAxisAlignment.start,                children: [                  Text(                    _title,                    style:                        Styles.textStyle18.copyWith(fontWeight: FontWeight.w900),                  ),                  const SizedBox(                    height: 20,                  ),                  ListView.separated(                    physics: const ClampingScrollPhysics(),                    shrinkWrap: true,                      scrollDirection: Axis.vertical,                      itemBuilder: (context, index) {                        var item =state.books[index] ;                        return Row(                            children: [                           SizedBox(                             width: MediaQuery.of(context).size.width *.25,                             child: AspectRatio(                                 aspectRatio: 2.5/4                                 ,child: Container(                               width: 100,                               height: 150,                               decoration: BoxDecoration(                                   image: DecorationImage(                                     image: NetworkImage(item.volumeInfo!                                         .imageLinks!                                         .thumbnail!),                                     fit: BoxFit.fill,                                     filterQuality: FilterQuality.high,                                   ),                                   borderRadius: const BorderRadius.all(                                       Radius.circular(20))),                             )),                           ),                              Expanded(                                child: Padding(                                  padding:                                      const EdgeInsets.only(left: 45, right: 20),                                  child: Column(                                    crossAxisAlignment: CrossAxisAlignment.start,                                    children: [                                      InkWell(                                          onTap: () => Navigator.push(                                              context,                                              MaterialPageRoute(                                                builder: (context) =>                                                    const ViewInformationBook(),                                              )),                                          child:  Text(                                            item.volumeInfo!.title.toString(),                                            style: Styles.textStyle20,                                            maxLines: 2,                                          )),                                      Text(                                        printName(item.volumeInfo!.authors!) ,                                        style: Styles.textStyle14.copyWith(                                            color: const Color(0xffc4c1c1)),                                      ),                                      const SizedBox(                                        height: 10,                                      ),                                      Row(                                        mainAxisAlignment:                                            MainAxisAlignment.spaceBetween,                                        children: [                                          Text(                                            isFree(item.saleInfo!),                                            style: Styles.textStyle20.copyWith(                                                fontWeight: FontWeight.w700,fontSize: 15),                                          ),                                          Row(                                            children: [                                              AppIcons.starOfRating,                                              Text(                                                "4.8",                                                style: Styles.textStyle14                                                    .copyWith(                                                        color: Colors.white),                                              ),                                              const SizedBox(                                                width: 5,                                              ),                                              Text(                                                "(2390)",                                                style: Styles.textStyle14                                                    .copyWith(                                                        color: const Color(                                                            0xff707070)),                                              ),                                            ],                                          )                                        ],                                      )                                    ],                                  ),                                ),                              )                            ],                          );                      },                      separatorBuilder: (context, index) => const SizedBox(                            height: 7,                          ),                      itemCount: state.books.length)                ],              ),            );        }        return Container();      },    );  }}